from playwright.sync_api import sync_playwright
import re
import os

GOOGLE_MAPS_URL = "https://share.google/VBUDEGd8VBNXWNVEC"
REVIEW_BATCH = "2026_week_21"
DOWNLOAD_FOLDER = f"weekly_reviews/{REVIEW_BATCH}"

# Hosts seen in Maps review / photo viewer
IMAGE_HOST_MARKERS = ("googleusercontent.com", "ggpht.com")

os.makedirs(DOWNLOAD_FOLDER, exist_ok=True)


def is_photo_url(url: str) -> bool:
    if not url or not url.startswith("http"):
        return False
    if not any(host in url for host in IMAGE_HOST_MARKERS):
        return False
    lowered = url.lower()
    # Skip tiny UI icons and profile avatars when possible
    if "/a-/" in lowered or "/a/" in lowered and "=s32" in lowered:
        return False
    if "favicon" in lowered or "logo" in lowered:
        return False
    return True


def clean_google_image_url(url: str) -> str:
    return re.sub(r"=s\d+.*$|=w\d+-h\d+.*$", "", url)


def normalize_url(url: str) -> str:
    return clean_google_image_url(url.split(" ")[0].strip())


EXTRACT_URLS_JS = """
() => {
  const urls = new Set();
  const add = (u) => {
    if (u && typeof u === "string" && u.startsWith("http")) urls.add(u);
  };

  const walk = (root) => {
    root.querySelectorAll("img").forEach((img) => {
      add(img.currentSrc);
      add(img.src);
      add(img.getAttribute("data-src"));
      const srcset = img.getAttribute("srcset");
      if (srcset) {
        srcset.split(",").forEach((part) => add(part.trim().split(" ")[0]));
      }
    });

    root.querySelectorAll("*").forEach((el) => {
      const bg = getComputedStyle(el).backgroundImage || "";
      const match = bg.match(/url\\(["']?(https:[^"')]+)/);
      if (match) add(match[1]);
      if (el.shadowRoot) walk(el.shadowRoot);
    });
  };

  walk(document);
  return [...urls];
}
"""


with sync_playwright() as p:
    browser = p.chromium.launch(headless=False)
    context = browser.new_context()
    page = context.new_page()

    # Capture every photo URL the browser loads while you click around
    network_urls: set[str] = set()

    def on_response(response):
        url = response.url
        if not is_photo_url(url):
            return
        try:
            body = response.body()
        except Exception:
            return
        if len(body) < 8_000:
            return
        network_urls.add(url)

    page.on("response", on_response)

    print("\nOpening Google Maps...\n")
    page.goto(GOOGLE_MAPS_URL, wait_until="domcontentloaded")
    page.wait_for_timeout(8000)

    print("MANUAL STEPS:")
    print("1. Open Reviews / Ulasan")
    print("2. Sort by Terbaru")
    print("3. Scroll recent reviews")
    print("4. Click ONE food photo")
    print("5. Wait until full-size viewer opens")
    print("(Network capture is ON — photos load as you click.)\n")
    input("Press ENTER when full-size photo is visible...")

    dom_urls = page.evaluate(EXTRACT_URLS_JS)
    dom_photo_urls = {u for u in dom_urls if is_photo_url(u)}

    candidates: dict[str, str] = {}
    for url in network_urls:
        candidates[normalize_url(url)] = url
    for url in dom_photo_urls:
        key = normalize_url(url)
        if key not in candidates:
            candidates[key] = url

    print("\n--- Debug ---")
    print(f"Network photo responses captured: {len(network_urls)}")
    print(f"DOM photo URLs found: {len(dom_photo_urls)}")
    print(f"Unique URLs to try downloading: {len(candidates)}")

    if network_urls:
        print("\nSample network URL:")
        print(next(iter(network_urls))[:120] + "...")
    elif dom_photo_urls:
        print("\nSample DOM URL:")
        print(next(iter(dom_photo_urls))[:120] + "...")
    else:
        print("\nNo photo URLs found.")
        print("Usually means the full-size viewer was NOT open yet.")
        print("Re-run and press ENTER only when the big black photo viewer is up.")
    print("-------------\n")

    downloaded = 0
    errors = 0

    for clean_key, original_url in sorted(candidates.items()):
        for attempt_url in (original_url, clean_key):
            try:
                print(f"Downloading image {downloaded}...")
                response = context.request.get(
                    attempt_url,
                    headers={"Referer": page.url},
                    timeout=30_000,
                )
                if not response.ok:
                    continue
                data = response.body()
                if len(data) < 8_000:
                    continue

                filepath = os.path.join(
                    DOWNLOAD_FOLDER, f"food_{downloaded}.jpg"
                )
                with open(filepath, "wb") as f:
                    f.write(data)

                downloaded += 1
                break
            except Exception as e:
                errors += 1
                print("ERROR:", e)

    print("===================================")
    print(f"Downloaded {downloaded} images")
    print(f"Saved to: {DOWNLOAD_FOLDER}")
    if errors:
        print(f"Failed attempts: {errors}")
    print("===================================\n")

    input("Press ENTER to close...")
    browser.close()
